import { useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { RichTextEditor } from "@/components/admin/RichTextEditor";
import { useToast } from "@/hooks/use-toast";
import { Save, Loader2, Eye } from "lucide-react";

const AdminAboutUs = () => {
  const { t } = useTranslation();
  const { toast } = useToast();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [contentId, setContentId] = useState<string | null>(null);
  const [contentZh, setContentZh] = useState("");
  const [contentEn, setContentEn] = useState("");
  const [contentPt, setContentPt] = useState("");

  useEffect(() => {
    fetchContent();
  }, []);

  const fetchContent = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from("about_us_content")
      .select("*")
      .limit(1)
      .single();

    if (data) {
      setContentId(data.id);
      setContentZh(data.content_zh || "");
      setContentEn(data.content_en || "");
      setContentPt(data.content_pt || "");
    }
    if (error) console.error("Error fetching about us content:", error);
    setLoading(false);
  };

  const handleSave = async () => {
    if (!contentId) return;
    setSaving(true);
    const { error } = await supabase
      .from("about_us_content")
      .update({
        content_zh: contentZh,
        content_en: contentEn,
        content_pt: contentPt,
        updated_at: new Date().toISOString(),
      })
      .eq("id", contentId);

    if (error) {
      toast({ title: t("common.error"), description: error.message, variant: "destructive" });
    } else {
      toast({ title: t("common.success"), description: t("common.actions.saved", "已保存") });
    }
    setSaving(false);
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">{t("admin.aboutUs", "关于我们")}</h1>
          <p className="text-muted-foreground text-sm mt-1">
            {t("admin.aboutUsDescription", "编辑「关于我们」页面的富文本内容")}
          </p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={() => window.open("/about-us", "_blank")}>
            <Eye className="w-4 h-4 mr-2" />
            {t("common.preview", "预览")}
          </Button>
          <Button onClick={handleSave} disabled={saving}>
            {saving ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Save className="w-4 h-4 mr-2" />}
            {t("common.actions.save")}
          </Button>
        </div>
      </div>

      <Tabs defaultValue="zh">
        <TabsList>
          <TabsTrigger value="zh">🇨🇳 中文</TabsTrigger>
          <TabsTrigger value="en">🇬🇧 English</TabsTrigger>
          <TabsTrigger value="pt">🇵🇹 Português</TabsTrigger>
        </TabsList>

        <TabsContent value="zh">
          <Card>
            <CardHeader>
              <CardTitle className="text-lg">中文内容</CardTitle>
            </CardHeader>
            <CardContent>
              <RichTextEditor
                value={contentZh}
                onChange={setContentZh}
                placeholder="输入中文内容..."
                className="min-h-[400px]"
              />
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="en">
          <Card>
            <CardHeader>
              <CardTitle className="text-lg">English Content</CardTitle>
            </CardHeader>
            <CardContent>
              <RichTextEditor
                value={contentEn}
                onChange={setContentEn}
                placeholder="Enter English content..."
                className="min-h-[400px]"
              />
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="pt">
          <Card>
            <CardHeader>
              <CardTitle className="text-lg">Conteúdo em Português</CardTitle>
            </CardHeader>
            <CardContent>
              <RichTextEditor
                value={contentPt}
                onChange={setContentPt}
                placeholder="Insira o conteúdo em português..."
                className="min-h-[400px]"
              />
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
};

export default AdminAboutUs;
